const raw = $input.all()[0].json.content[0].text.trim();
const cleaned = raw.replace(/^```(?:json)?\s*/,'').replace(/\s*```$/,'');
const profile = JSON.parse(cleaned);
const config = {
  resumePath: $('Load Config').item.json.resumePath,
  emailRecipient: $('Load Config').item.json.emailRecipient,
  anthropicKey: $('Load Config').item.json.anthropicKey,
  braveKey: $('Load Config').item.json.braveKey,
  topN: $('Load Config').item.json.topN,
  indiaPortals: $('Load Config').item.json.indiaPortals.split(','),
  usPortals: $('Load Config').item.json.usPortals.split(',')
};
return [{ json: { profile, config } }];

const raw = $input.all()[0].json.content[0].text.trim().replace(/^```(?:json)?\s*/,'').replace(/\s*```$/,'');
const queries = JSON.parse(raw);
const profile = $('Extract Profile JSON').item.json.profile;
const config = $('Extract Profile JSON').item.json.config;

const tasks = [];
for (const query of queries) {
  for (const portal of config.indiaPortals) {
    tasks.push({ json: { query, portal, country: 'India', siteQuery: `site:${portal} ${query} India`, profile, config } });
  }
  for (const portal of config.usPortals) {
    tasks.push({ json: { query, portal, country: 'US', siteQuery: `site:${portal} ${query}`, profile, config } });
  }
}
return tasks;

const results = [];
for (const item of $input.all()) {
  const raw = item.json;
  const portal = raw.portal || '';
  const country = raw.country || '';
  const webResults = raw.web?.results || [];
  for (const r of webResults) {
    const snippet = r.description || '';
    const title = r.title || '';
    const expMatch = snippet.match(/(\d+[\-–]\d+|\d+\+?)\s*(?:years?|yrs?)/i);
    const dateMatch = snippet.match(/(\d+\s+(?:day|hour|week|month)s?\s+ago|today|just\s+posted)/i);
    const locMatch = snippet.match(/\b(Mumbai|Delhi|NCR|Bangalore|Bengaluru|Chennai|Hyderabad|Pune|Kolkata|Noida|Gurgaon|Patna|Bihar|Rajasthan|Jharkhand|New York|San Francisco|Seattle|Austin|Chicago|Boston|Remote)\b/i);
    const coMatch = title.match(/ at ([^|–\-]+)/);
    results.push({
      title: title,
      company: coMatch ? coMatch[1].trim() : '',
      location: locMatch ? locMatch[1] : '',
      experience_required: expMatch ? expMatch[0] : '',
      posted_date: dateMatch ? dateMatch[0] : '',
      snippet: snippet,
      url: r.url || '',
      portal: portal,
      country: country
    });
  }
}
return results.map(j => ({ json: j }));

const raw = $input.all()[0].json.content[0].text.trim().replace(/^```(?:json)?\s*/,'').replace(/\s*```$/,'');
const ranked = JSON.parse(raw);
return [{ json: { rankedJobs: ranked, profile: $('Extract Profile JSON').item.json.profile, config: $('Extract Profile JSON').item.json.config } }];

const atsRaw = $input.all()[0].json.content[0].text.trim().replace(/^```(?:json)?\s*/,'').replace(/\s*```$/,'');
const ats = JSON.parse(atsRaw);
const rankedJobs = $('Parse Ranked Jobs').item.json.rankedJobs;
const profile = $('Parse Ranked Jobs').item.json.profile;
const config = $('Parse Ranked Jobs').item.json.config;

const today = new Date().toLocaleDateString('en-GB', { day:'2-digit', month:'short', year:'numeric' });
const name = profile.name || 'there';
const exp = profile.total_experience_years || '?';
const roles = (profile.target_roles || []).slice(0,3).join(' | ');

// Build plain text
let plain = `Hi ${name},\n\nYour top ${Math.min(config.topN, rankedJobs.length)} job matches for ${today}.\nProfile: ${exp} yrs | ${profile.profession_category} | ${roles}\n\n${'='.repeat(60)}\nJOB MATCHES\n${'='.repeat(60)}\n`;
for (let i = 0; i < Math.min(config.topN, rankedJobs.length); i++) {
  const j = rankedJobs[i];
  const flag = j.country === 'India' ? '(India)' : '(US)';
  plain += `\nRANK ${i+1} ${flag} | Score: ${j.total_score || 0}/65 (${j.relevance_pct || 0}%)\n`;
  plain += `Title   : ${j.title || 'N/A'}\n`;
  plain += `Company : ${j.company || 'N/A'}\n`;
  plain += `Location: ${j.location || 'N/A'}\n`;
  plain += `Exp Req : ${j.experience_required || 'Not specified'}\n`;
  plain += `Why?    : ${j.match_reason || ''}\n`;
  plain += `Apply   : ${j.url || 'N/A'}\n`;
  plain += `${'-'.repeat(60)}\n`;
}
plain += `\n${'='.repeat(60)}\nATS REPORT\n${'='.repeat(60)}\n`;
plain += `Current ATS score : ${ats.ats_score_before}/100\n`;
plain += `Projected (after) : ${ats.ats_score_after}/100\n\nMISSING KEYWORDS:\n`;
(ats.missing_keywords || []).slice(0,8).forEach(k => {
  plain += `  + ${k.keyword}  →  ${k.suggested_placement}\n`;
  if (k.sample_phrase) plain += `    e.g. "${k.sample_phrase}"\n`;
});
if (ats.optimized_summary) plain += `\nSUGGESTED SUMMARY:\n  "${ats.optimized_summary}"\n`;
plain += `\nPowered by Agentic Job Search — https://github.com/shubhamsinha89/Agentic-Job-Search`;

// Build HTML
const pctColor = p => p >= 80 ? '#22c55e' : p >= 60 ? '#f59e0b' : '#ef4444';
const rows = rankedJobs.slice(0, config.topN).map((j,i) => `
  <tr style="border-bottom:1px solid #e5e7eb">
    <td style="padding:10px;font-weight:600">${i+1}. ${j.country==='India'?'🇮🇳':'🇺🇸'}</td>
    <td style="padding:10px">
      <strong><a href="${j.url||'#'}" style="color:#2563eb;text-decoration:none">${j.title||'N/A'}</a></strong><br>
      <span style="color:#6b7280;font-size:13px">${j.company||''} · ${j.location||''}</span><br>
      <span style="color:#9ca3af;font-size:12px">${j.portal||''} · ${j.posted_date||''}</span><br>
      <span style="color:#4b5563;font-size:12px;font-style:italic">${j.match_reason||''}</span>
    </td>
    <td style="padding:10px;text-align:center">
      <span style="background:${pctColor(j.relevance_pct||0)};color:white;padding:3px 9px;border-radius:10px;font-weight:700;font-size:13px">${j.relevance_pct||0}%</span><br>
      <span style="font-size:11px;color:#9ca3af">${j.total_score||0}/65</span>
    </td>
    <td style="padding:10px;font-size:12px;color:#6b7280">${j.experience_required||'N/A'}</td>
  </tr>`).join('');

const missingKwHtml = (ats.missing_keywords||[]).slice(0,8).map(k =>
  `<li><strong>${k.keyword}</strong> → <em>${k.suggested_placement}</em>${k.sample_phrase ? ` — "${k.sample_phrase}"` : ''}</li>`
).join('');

const html = `<!DOCTYPE html><html><body style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;max-width:800px;margin:0 auto;padding:20px;color:#1f2937">
<div style="background:linear-gradient(135deg,#2563eb,#7c3aed);padding:24px;border-radius:12px;color:white;margin-bottom:24px">
  <h1 style="margin:0 0 6px 0;font-size:20px">Your Daily Job Digest — ${today}</h1>
  <p style="margin:0;opacity:.9">${name} · ${exp} yrs · ${profile.profession_category}</p>
  <p style="margin:4px 0 0;opacity:.8;font-size:13px">${roles}</p>
</div>
<h2 style="border-bottom:2px solid #e5e7eb;padding-bottom:8px">Top ${Math.min(config.topN, rankedJobs.length)} Matches</h2>
<table style="width:100%;border-collapse:collapse;font-size:13px">
  <thead><tr style="background:#f9fafb;border-bottom:2px solid #e5e7eb">
    <th style="padding:8px;text-align:left;color:#6b7280">#</th>
    <th style="padding:8px;text-align:left;color:#6b7280">Role</th>
    <th style="padding:8px;text-align:center;color:#6b7280">Match</th>
    <th style="padding:8px;text-align:left;color:#6b7280">Exp</th>
  </tr></thead>
  <tbody>${rows}</tbody>
</table>
<div style="background:#fefce8;border:1px solid #fde68a;border-radius:8px;padding:18px;margin-top:24px">
  <h2 style="margin:0 0 10px;color:#92400e;font-size:15px">ATS Optimization — Score: ${ats.ats_score_before}/100 → ${ats.ats_score_after}/100</h2>
  <strong style="color:#78350f">Add these keywords to your resume:</strong>
  <ul style="font-size:13px;color:#78350f;margin:8px 0">${missingKwHtml}</ul>
  ${ats.optimized_summary ? `<p style="font-size:13px;color:#78350f"><strong>Suggested summary:</strong> "${ats.optimized_summary}"</p>` : ''}
</div>
<p style="font-size:11px;color:#9ca3af;margin-top:20px;text-align:center">
  Powered by <a href="https://github.com/shubhamsinha89/Agentic-Job-Search" style="color:#2563eb">Agentic Job Search</a> · India + US portals
</p></body></html>`;

return [{ json: {
  subject: `Top ${Math.min(config.topN, rankedJobs.length)} Job Matches – ${today}`,
  to: config.emailRecipient,
  plain,
  html
} }];
